import os
from rediscluster import RedisCluster

# Define environment variables for Redis cluster configuration
REDIS_NODES = [
    {'host': 'node1', 'port': 7000},
    {'host': 'node2', 'port': 7000},
    {'host': 'node3', 'port': 7000}
]

startup_nodes = {
    "hosts": REDIS_NODES,
    "max_connections_per_node": 1024
}

redis_cluster = RedisCluster(startup_nodes=startup_nodes, decode_responses=True)

# Function to set user data with TTL (time to live)
def set_user_data(user_id, session_token, api_key):
    redis_cluster.set(f"user:{user_id}:session", session_token, ex=3600)  # 1 hour
    redis_cluster.set(f"user:{user_id}:api_key", api_key, ex=86400)  # 24 hours

# Function to get user data from Redis
def get_user_data(user_id):
    return redis_cluster.get(f"user:{user_id}:session"), redis_cluster.get(f"user:{user_id}:api_key")

# Example usage:
